# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

users = {}  # This would be your database in a real scenario

@app.route('/profile/update', methods=['POST'])
def update_profile():
    data = request.get_json()
    
    if 'email' not in data or 'password' not in data:
        return {'error': 'Missing email and/or password'}, 400
        
    user_id = request.cookies.get('session')   # Assumes session id is stored as a cookie
    
    if user_id not in users:
        return {'error': 'Invalid session'}, 401
        
    user = users[user_id]
    
    # Check and update password (optional, see the 2FA section for more)
    if check_password_hash(user['password'], data['old_password']):
        user['password'] = generate_password_hash(data['new_password'])
    else:
        return {'error': 'Incorrect old password'}, 401
        
    # Check and update email (optional, see the 2FA section for more)
    if 'email' in data:
        user['email'] = data['email']
    
    users[user_id] = user   # Update user info in database
    
    return {'message': 'Profile updated successfully'}, 200